import {
  Component, OnInit, OnDestroy, Output, EventEmitter,
  ElementRef, ViewChild, HostListener
} from '@angular/core';
import { Subject, Subscription } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap, filter } from 'rxjs/operators';
import { NetsuiteService } from '../../services/netsuite.service';
import { BookingFormService } from '../../services/booking-form.service';
import { BookingRecord } from '../../models/booking-form.model';

@Component({
  selector: 'app-customer-search',
  templateUrl: './customer-search.component.html',
  styleUrls: ['./customer-search.component.scss']
})
export class CustomerSearchComponent implements OnInit, OnDestroy {

  @Output() recordLoaded = new EventEmitter<BookingRecord>();
  @Output() loading       = new EventEmitter<boolean>();
  @ViewChild('searchInput') searchInputRef!: ElementRef<HTMLInputElement>;

  // Search input binding
  searchTerm = '';

  // Dropdown state
  results:     BookingRecord[] = [];
  isOpen       = false;
  isSearching  = false;
  searchError  = '';
  noResults    = false;

  // Selected / loaded record state
  selectedRecord: BookingRecord | null = null;
  isLoadingDetail = false;
  loadError        = '';
  isLoaded         = false;

  // Confirmation modal state (shown before overwriting a partially filled form)
  showConfirm     = false;
  pendingRecord:  BookingRecord | null = null;

  private search$   = new Subject<string>();
  private subs      = new Subscription();

  constructor(
    private ns:  NetsuiteService,
    private svc: BookingFormService
  ) {}

  ngOnInit(): void {
    this.subs.add(
      this.search$.pipe(
        debounceTime(400),
        distinctUntilChanged(),
        filter(v => v.trim().length >= 2),   // min 2 chars to search
        switchMap(term => {
          this.isSearching = true;
          this.noResults   = false;
          this.searchError = '';
          this.results     = [];
          return this.ns.searchBookingRecords(term);
        })
      ).subscribe({
        next: res => {
          this.isSearching = false;
          this.results     = res.records || [];
          this.noResults   = this.results.length === 0;
          this.isOpen      = true;
        },
        error: err => {
          this.isSearching = false;
          this.searchError = 'Search failed — please try again';
          this.results     = [];
        }
      })
    );
  }

  ngOnDestroy(): void { this.subs.unsubscribe(); }

  // ── Triggered on every keystroke ────────────────────────────────
  onInput(value: string): void {
    this.searchTerm = value;
    if (value.trim().length < 2) {
      this.isOpen    = false;
      this.results   = [];
      this.noResults = false;
      return;
    }
    this.isSearching = true;   // show spinner immediately
    this.search$.next(value.trim());
  }

  // ── User picks a result from the dropdown ───────────────────────
  selectResult(rec: BookingRecord): void {
    this.isOpen      = false;
    this.searchTerm  = rec.displayLabel;

    // If form has data already, ask for confirmation before overwriting
    const hasData = this.svc.hasUnsavedData();
    if (hasData) {
      this.pendingRecord  = rec;
      this.showConfirm    = true;
    } else {
      this.loadBookingDetail(rec);
    }
  }

  // ── Confirmation: proceed ───────────────────────────────────────
  confirmLoad(): void {
    this.showConfirm = false;
    if (this.pendingRecord) this.loadBookingDetail(this.pendingRecord);
    this.pendingRecord = null;
  }

  // ── Confirmation: cancel ────────────────────────────────────────
  cancelLoad(): void {
    this.showConfirm = false;
    this.pendingRecord = null;
    this.searchTerm = '';
  }

  // ── Load full booking record by ID and bind to form ─────────────
  private loadBookingDetail(rec: BookingRecord): void {
    this.isLoadingDetail = true;
    this.isLoaded        = false;
    this.loadError       = '';
    this.selectedRecord  = rec;
    this.loading.emit(true);          // ← tell parent: show overlay spinner

    this.ns.loadBookingRecord(rec.bookingId).subscribe({
      next: (full: BookingRecord) => {
        this.isLoadingDetail = false;
        this.isLoaded        = true;
        this.selectedRecord  = full;
        this.loading.emit(false);     // ← hide overlay spinner

        // Bind all sections back into the form service
        this.svc.loadFromBookingRecord(full);

        this.recordLoaded.emit(full);
      },
      error: (err) => {
        this.isLoadingDetail = false;
        this.loadError       = `Could not load record: ${err.message}`;
        this.loading.emit(false);     // ← hide overlay spinner on error
      }
    });
  }

  // ── Clear the selection ─────────────────────────────────────────
  clear(): void {
    this.searchTerm     = '';
    this.results        = [];
    this.isOpen         = false;
    this.selectedRecord = null;
    this.isLoaded       = false;
    this.loadError      = '';
    this.noResults      = false;
    this.svc.reset();
    setTimeout(() => this.searchInputRef?.nativeElement.focus(), 50);
  }

  // ── Close dropdown when clicking outside ────────────────────────
  @HostListener('document:click', ['$event'])
  onDocClick(e: MouseEvent): void {
    if (!(e.target as HTMLElement).closest('.cs-wrap')) {
      this.isOpen = false;
    }
  }
}
<div class="cs-wrap">

  <!-- ── Search Bar ── -->
  <div class="cs-search-row" [class.cs-has-value]="isLoaded">

    <div class="cs-icon">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
        <circle cx="11" cy="11" r="8"/><path d="M21 21l-4.35-4.35"/>
      </svg>
    </div>

    <input
      #searchInput
      class="cs-input"
      type="text"
      [value]="searchTerm"
      (input)="onInput($any($event.target).value)"
      placeholder="Search existing booking — name, mobile, flat no., booking ID…"
      autocomplete="off"
      [readonly]="isLoaded"
    />

    <!-- Spinner while searching -->
    <span class="cs-spinner" *ngIf="isSearching"></span>

    <!-- Clear button once a record is loaded -->
    <button class="cs-clear-btn" *ngIf="isLoaded" (click)="clear()" title="Clear and start new">
      ✕ Clear
    </button>

  </div>

  <!-- ── Dropdown Results ── -->
  <div class="cs-dropdown" *ngIf="isOpen && !isLoaded">

    <!-- Loading row -->
    <div class="cs-row cs-loading" *ngIf="isSearching">
      <span class="cs-spin-sm"></span> Searching NetSuite…
    </div>

    <!-- No results -->
    <div class="cs-row cs-empty" *ngIf="noResults && !isSearching">
      No booking records found for "<strong>{{ searchTerm }}</strong>"
    </div>

    <!-- Error -->
    <div class="cs-row cs-err" *ngIf="searchError">
      ⚠ {{ searchError }}
    </div>

    <!-- Results list -->
    <div
      class="cs-result-row"
      *ngFor="let r of results"
      (click)="selectResult(r)"
    >
      <div class="cs-result-left">
        <span class="cs-result-name">{{ r.customerName }}</span>
        <span class="cs-result-sub">
          {{ r.projectName || '—' }}
          <ng-container *ngIf="r.wing || r.flatNo"> · {{ r.wing }}-{{ r.flatNo }}</ng-container>
        </span>
      </div>
      <div class="cs-result-right">
        <span class="cs-result-mobile">{{ r.mobile }}</span>
        <span class="cs-result-id">ID {{ r.bookingId }}</span>
      </div>
    </div>

  </div>

  <!-- ── Loaded Record Badge ── -->
  <div class="cs-loaded-badge" *ngIf="isLoaded && selectedRecord">
    <div class="cs-loaded-left">
      <span class="cs-badge-icon">📋</span>
      <div>
        <div class="cs-badge-name">{{ selectedRecord.customerName }}</div>
        <div class="cs-badge-sub">
          Booking #{{ selectedRecord.bookingId }}
          <ng-container *ngIf="selectedRecord.projectName"> · {{ selectedRecord.projectName }}</ng-container>
          <ng-container *ngIf="selectedRecord.wing || selectedRecord.flatNo">
            · {{ selectedRecord.wing }}-{{ selectedRecord.flatNo }}
          </ng-container>
        </div>
      </div>
    </div>
    <div class="cs-loaded-right">
      <span class="cs-loaded-tick">✓ Form populated</span>
    </div>
  </div>

  <!-- ── Loading spinner while fetching full record ── -->
  <div class="cs-loading-record" *ngIf="isLoadingDetail">
    <span class="cs-spin-sm"></span>
    Loading booking record…
  </div>

  <!-- ── Load error ── -->
  <div class="cs-load-error" *ngIf="loadError">
    ⚠ {{ loadError }}
    <button (click)="clear()">Dismiss</button>
  </div>

  <!-- ── Confirmation modal ── -->
  <div class="cs-modal-backdrop" *ngIf="showConfirm">
    <div class="cs-modal">
      <div class="cs-modal-icon">⚠</div>
      <h4>Overwrite current form data?</h4>
      <p>
        The form already has unsaved data. Loading
        <strong>{{ pendingRecord?.displayLabel }}</strong>
        will replace all current entries.
      </p>
      <div class="cs-modal-actions">
        <button class="cs-btn-cancel" (click)="cancelLoad()">Cancel</button>
        <button class="cs-btn-confirm" (click)="confirmLoad()">Yes, load record</button>
      </div>
    </div>
  </div>

</div>
